module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [1:0] mul_en_out_reg;
reg [size-1:0] mul_a_reg, mul_b_reg;
wire [size*2-1:0] temp;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_en_out_reg <= 2'b0;
    end
    else begin
        mul_en_out_reg <= {mul_en_out_reg[0], mul_en_in};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
    else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end

assign temp = {1'b0, mul_a} * {1'b0, mul_b};

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_en_out <= 1'b0;
    end
    else begin
        mul_en_out <= mul_en_out_reg[2];
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_out <= 0;
    end
    else begin
        mul_out <= temp[size*2-1:0];
    end
end

endmodule
